Code.Terraform:
```hcl
resource "aws_networkfirewall_logging_configuration" "<example_resource_name>" {
  firewall_arn = "<example_resource_id>"  # 关键：定位防火墙以启用日志记录

  logging_configuration {
    log_destination_config {
      log_type             = "FLOW"              # 关键：启用至少一种日志类型
      log_destination_type = "CloudWatchLogs"   # 关键：选择有效的目标类型
      log_destination = {
        logGroup = "<example_log_group_name>"   # 关键：现有的 CloudWatch Logs 组以接收日志
      }
    }
  }
}
```
